INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'fort-worth'), 'A-5', 'a-5', 'One-Family', 'This district is intended for one-family detached dwellings with a minimum lot size of 5,000 square feet, along with compatible civic uses.', NULL, NULL, 5000, NULL, 20, 25, NULL, 'Fort Worth''s baseline table still governs (e.g., 1–4 spaces per dwelling in some residential districts, plus multifamily formulas). Parking spaces must be hard-surfaced and dust free.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'a-5' AND z.city_id = (SELECT id FROM cities WHERE slug = 'fort-worth') AND pu.name IN ('One-family detached dwellings', 'Churches', 'Schools', 'Parks') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'fort-worth'), 'B', 'b', 'Two-Family', 'This district allows for one-family and two-family detached and attached dwellings, with varying minimum lot sizes based on dwelling type.', NULL, NULL, 5000, NULL, 20, 25, NULL, 'Fort Worth''s baseline table still governs (e.g., 1–4 spaces per dwelling in some residential districts, plus multifamily formulas). Parking spaces must be hard-surfaced and dust free.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'b' AND z.city_id = (SELECT id FROM cities WHERE slug = 'fort-worth') AND pu.name IN ('One-family detached dwellings', 'Two-family detached dwellings', 'One-family attached dwellings', 'Two-family attached dwellings', 'Churches', 'Schools', 'Parks') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'fort-worth'), 'C', 'c', 'Medium Density Multifamily', 'This district is designated for multifamily dwelling units with a maximum density of 18 dwelling units per acre.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Fort Worth''s baseline table still governs (e.g., 1–4 spaces per dwelling in some residential districts, plus multifamily formulas). A multi-family development permit (MFD) is required.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'c' AND z.city_id = (SELECT id FROM cities WHERE slug = 'fort-worth') AND pu.name IN ('Multifamily dwelling units') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'fort-worth'), 'UR', 'ur', 'Urban Residential', 'This district provides a higher density, residential-only, pedestrian-oriented development, serving as a transition zone between low-density single-family neighborhoods and higher-density commercial areas.', 42, NULL, NULL, NULL, 20, 20, NULL, 'Single Family Detached: 2 spaces per dwelling unit. Townhouse: 1-2 spaces per dwelling unit. Duplex & Manor House (2+ units): 1-2 spaces per dwelling unit plus 1 space per bedroom over three. Apartments/Condominiums: 0.5-1 space per bedroom plus 2 spaces per 500 sq ft of leasing/social rooms. On-street parking may not count toward required parking.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'ur' AND z.city_id = (SELECT id FROM cities WHERE slug = 'fort-worth') AND pu.name IN ('Single-family detached dwellings', 'Townhouses', 'Duplexes', 'Manor Houses (2+ units)', 'Apartments/Condominiums') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'fort-worth'), 'F', 'f', 'General Commercial', 'This district permits general commercial uses, including amusement establishments, and allows for alcohol sales and on-premises consumption.', 45, NULL, NULL, NULL, NULL, NULL, NULL, 'Most retail stores require 1 space per 200 square feet of gross floor area. Supplemental standards apply when adjacent to residential districts.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'f' AND z.city_id = (SELECT id FROM cities WHERE slug = 'fort-worth') AND pu.name IN ('Amusement (nightclubs, pool halls, taverns, skating rinks)', 'Used furniture stores', 'Alcohol sales and on-premises consumption', 'Mini-warehouses') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'fort-worth'), 'G', 'g', 'Intensive Commercial', 'This district allows for intensive commercial uses, including all uses permitted in ''F'', plus other retail uses not considered offensive or noxious, with less restrictive area regulations.', 120, NULL, NULL, NULL, NULL, NULL, NULL, 'Most retail stores require 1 space per 200 square feet of gross floor area. Supplemental standards apply when adjacent to residential districts.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'g' AND z.city_id = (SELECT id FROM cities WHERE slug = 'fort-worth') AND pu.name IN ('All uses permitted in ''F''', 'Other retail uses not considered offensive or noxious', 'Alcohol sales and on-premises consumption', 'Mini-warehouses') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'fort-worth'), 'I', 'i', 'Light Industrial', 'This district permits light industrial uses, including all uses allowed in ''G'', along with food processing, warehousing, and light manufacturing.', 55, NULL, NULL, NULL, NULL, NULL, NULL, 'Parking requirements are based on the use and size of the establishment. Hard surface parking is not required for non-passenger vehicles and tractor trailers for industrial uses.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
