INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'fort-worth'), 'J', 'j', 'Medium Industrial', 'This district allows for medium industrial uses, including all uses permitted in ''I'', plus breweries, cement products, and power plants.', 120, NULL, NULL, NULL, NULL, NULL, NULL, 'Parking requirements are based on the use and size of the establishment. Hard surface parking is not required for non-passenger vehicles and tractor trailers for industrial uses.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'j' AND z.city_id = (SELECT id FROM cities WHERE slug = 'fort-worth') AND pu.name IN ('All uses permitted in ''I''', 'Breweries', 'Cement products', 'Power plants', 'Grain elevators', 'Poultry slaughtering', 'Light manufacturing', 'Alcohol sales and on-premises consumption') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'fort-worth'), 'MU-1', 'mu-1', 'Low Intensity Mixed-Use', 'This district encourages higher density, mixed-use, pedestrian-oriented development, concentrating a variety of housing types among neighborhood-serving commercial and institutional uses.', 60, NULL, NULL, NULL, 20, NULL, NULL, 'Parking requirements are for commercial and mixed-use parking, and residential parking. For mixed-use or multifamily in commercial zones, the city can''t require more than one space per dwelling unit.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
