INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'fort-worth'), 'MU-2', 'mu-2', 'High Intensity Mixed-Use', 'This district promotes higher density, mixed-use, pedestrian-oriented development, concentrating a variety of housing types among commercial, institutional, and select light industrial uses.', 120, NULL, NULL, NULL, 20, 5, 20, 'Parking requirements are for commercial and mixed-use parking, and residential parking. For mixed-use or multifamily in commercial zones, the city can''t require more than one space per dwelling unit.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
